import type { QueryClient } from "@tanstack/react-query"
import { formatMessage } from "@voyantjs/i18n"
import {
  defaultFetcher,
  getLegalContractNumberSeriesQueryOptions,
  useLegalContractNumberSeries,
  useLegalContractNumberSeriesMutation,
} from "@voyantjs/legal-react"
import { Loader2, Pencil, Plus, Trash2 } from "lucide-react"
import { useState } from "react"

import { Badge, Button } from "@/components/ui"

import { useRegistryLegalMessagesOrDefault } from "./i18n/provider"
import { type NumberSeriesData, NumberSeriesDialog } from "./number-series-dialog"

type EnsureQueryData = QueryClient["ensureQueryData"]

export function loadNumberSeriesPage(ensureQueryData: EnsureQueryData) {
  return ensureQueryData(
    getLegalContractNumberSeriesQueryOptions({ baseUrl: "", fetcher: defaultFetcher }),
  )
}

export function NumberSeriesPage() {
  const m = useRegistryLegalMessagesOrDefault()
  const [dialogOpen, setDialogOpen] = useState(false)
  const [editingSeries, setEditingSeries] = useState<NumberSeriesData | undefined>()
  const { remove } = useLegalContractNumberSeriesMutation()
  const { data, isPending, refetch } = useLegalContractNumberSeries()
  const rows = data?.data ?? []

  return (
    <div className="flex flex-col gap-6 p-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">{m.numberSeriesPage.title}</h1>
          <p className="text-sm text-muted-foreground">{m.numberSeriesPage.description}</p>
        </div>
        <Button
          onClick={() => {
            setEditingSeries(undefined)
            setDialogOpen(true)
          }}
        >
          <Plus className="mr-2 h-4 w-4" />
          {m.numberSeriesPage.create}
        </Button>
      </div>

      {isPending ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </div>
      ) : null}

      {!isPending && rows.length === 0 ? (
        <div className="rounded-md border border-dashed p-8 text-center">
          <p className="text-sm text-muted-foreground">{m.numberSeriesPage.empty}</p>
        </div>
      ) : null}

      {!isPending && rows.length > 0 ? (
        <div className="rounded border bg-background">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b text-muted-foreground">
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.name}</th>
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.prefix}</th>
                <th className="p-3 text-left font-medium">
                  {m.numberSeriesPage.columns.separator}
                </th>
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.pad}</th>
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.current}</th>
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.reset}</th>
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.scope}</th>
                <th className="p-3 text-left font-medium">{m.numberSeriesPage.columns.status}</th>
                <th className="w-20 p-3" />
              </tr>
            </thead>
            <tbody>
              {rows.map((series) => (
                <tr key={series.id} className="border-b last:border-b-0">
                  <td className="p-3">{series.name}</td>
                  <td className="p-3 font-mono">{series.prefix || m.common.noResultsDash}</td>
                  <td className="p-3 font-mono">{series.separator || m.common.noResultsDash}</td>
                  <td className="p-3">{series.padLength}</td>
                  <td className="p-3 font-mono">{series.currentSequence}</td>
                  <td className="p-3">
                    {m.common.resetStrategyLabels[
                      series.resetStrategy as keyof typeof m.common.resetStrategyLabels
                    ] ?? series.resetStrategy}
                  </td>
                  <td className="p-3">
                    <Badge variant="outline">{m.common.contractScopeLabels[series.scope]}</Badge>
                  </td>
                  <td className="p-3">
                    <Badge variant={series.active ? "default" : "secondary"}>
                      {series.active ? m.common.active : m.common.inactive}
                    </Badge>
                  </td>
                  <td className="p-3">
                    <div className="flex items-center gap-1">
                      <button
                        type="button"
                        onClick={() => {
                          setEditingSeries(series)
                          setDialogOpen(true)
                        }}
                        className="text-muted-foreground hover:text-foreground"
                      >
                        <Pencil className="h-3.5 w-3.5" />
                      </button>
                      <button
                        type="button"
                        onClick={() => {
                          if (
                            confirm(
                              formatMessage(m.numberSeriesPage.confirms.deleteSeries, {
                                name: series.name,
                              }),
                            )
                          ) {
                            remove.mutate(series.id, { onSuccess: () => void refetch() })
                          }
                        }}
                        className="text-muted-foreground hover:text-destructive"
                      >
                        <Trash2 className="h-3.5 w-3.5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : null}

      <NumberSeriesDialog
        open={dialogOpen}
        onOpenChange={setDialogOpen}
        series={editingSeries}
        onSuccess={() => {
          setDialogOpen(false)
          setEditingSeries(undefined)
          void refetch()
        }}
      />
    </div>
  )
}

import { formatMessage } from "@voyantjs/i18n"
import {
  type LegalContractNumberSeriesRecord,
  useLegalContractNumberSeries,
  useLegalContractNumberSeriesMutation,
} from "@voyantjs/legal-react"
import { Loader2 } from "lucide-react"
import { useEffect, useMemo } from "react"
import { useForm } from "react-hook-form"
import { z } from "zod/v4"

import {
  Button,
  Dialog,
  DialogBody,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Input,
  Label,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui"
import { Switch } from "@/components/ui/switch"
import { zodResolver } from "@/lib/zod-resolver"

import { useRegistryLegalMessagesOrDefault } from "./i18n/provider"

type FormValues = {
  name: string
  prefix: string
  separator?: string
  padLength?: number
  resetStrategy: "never" | "annual" | "monthly"
  scope: "customer" | "supplier" | "partner" | "channel" | "other"
  active: boolean
}

export type NumberSeriesData = LegalContractNumberSeriesRecord

type NumberSeriesDialogProps = {
  open: boolean
  onOpenChange: (open: boolean) => void
  series?: NumberSeriesData
  onSuccess: () => void
}

function createSeriesFormSchema(messages: ReturnType<typeof useRegistryLegalMessagesOrDefault>) {
  return z.object({
    name: z.string().min(1, messages.numberSeriesDialog.validation.nameRequired).max(255),
    prefix: z.string().min(1, messages.numberSeriesDialog.validation.prefixRequired).max(20),
    separator: z.string().max(5).optional(),
    padLength: z.coerce.number().int().min(0).max(12).optional(),
    resetStrategy: z.enum(["never", "annual", "monthly"]),
    scope: z.enum(["customer", "supplier", "partner", "channel", "other"]),
    active: z.boolean(),
  })
}

const RESET_STRATEGIES = ["never", "annual", "monthly"] as const
const SCOPES = ["customer", "supplier", "partner", "channel", "other"] as const

export function NumberSeriesDialog({
  open,
  onOpenChange,
  series,
  onSuccess,
}: NumberSeriesDialogProps) {
  const messages = useRegistryLegalMessagesOrDefault()
  const seriesFormSchema = createSeriesFormSchema(messages)
  const isEditing = !!series
  const { create, update } = useLegalContractNumberSeriesMutation()
  const { data: existingList } = useLegalContractNumberSeries()

  const form = useForm<FormValues>({
    resolver: zodResolver(seriesFormSchema),
    defaultValues: {
      name: "",
      prefix: "",
      separator: "",
      padLength: 4,
      resetStrategy: "never",
      scope: "customer",
      active: true,
    },
  })

  useEffect(() => {
    if (open && series) {
      form.reset({
        name: series.name,
        prefix: series.prefix,
        separator: series.separator,
        padLength: series.padLength,
        resetStrategy: series.resetStrategy as FormValues["resetStrategy"],
        scope: series.scope as FormValues["scope"],
        active: series.active,
      })
    } else if (open) {
      form.reset()
    }
  }, [open, series, form])

  const watchedPrefix = form.watch("prefix")
  const watchedScope = form.watch("scope")
  const watchedActive = form.watch("active")

  // The DB has a partial unique index on (prefix, scope) WHERE active.
  // Surface the collision before submit so the operator gets a friendly
  // hint instead of an opaque server error.
  const conflictingSeries = useMemo(() => {
    if (!watchedActive || !watchedPrefix) return null
    const rows = existingList?.data ?? []
    return (
      rows.find(
        (row) =>
          row.active &&
          row.prefix === watchedPrefix &&
          row.scope === watchedScope &&
          row.id !== series?.id,
      ) ?? null
    )
  }, [existingList, watchedActive, watchedPrefix, watchedScope, series?.id])

  const onSubmit = async (values: FormValues) => {
    const payload = {
      name: values.name,
      prefix: values.prefix,
      separator: values.separator || "",
      padLength: values.padLength ?? 4,
      resetStrategy: values.resetStrategy,
      scope: values.scope,
      active: values.active,
    }

    if (isEditing && series) {
      await update.mutateAsync({ id: series.id, input: payload })
    } else {
      await create.mutateAsync(payload)
    }
    onSuccess()
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>
            {isEditing
              ? messages.numberSeriesDialog.titles.edit
              : messages.numberSeriesDialog.titles.create}
          </DialogTitle>
        </DialogHeader>
        <form onSubmit={form.handleSubmit(onSubmit)}>
          <DialogBody className="grid gap-4">
            <div className="flex flex-col gap-2">
              <Label>{messages.numberSeriesDialog.fields.name}</Label>
              <Input
                {...form.register("name")}
                placeholder={messages.numberSeriesDialog.placeholders.name}
              />
              {form.formState.errors.name ? (
                <p className="text-xs text-destructive">{form.formState.errors.name.message}</p>
              ) : null}
            </div>

            <div className="grid grid-cols-3 gap-4">
              <div className="flex flex-col gap-2">
                <Label>{messages.numberSeriesDialog.fields.prefix}</Label>
                <Input
                  {...form.register("prefix")}
                  placeholder={messages.numberSeriesDialog.placeholders.prefix}
                  maxLength={20}
                />
                {form.formState.errors.prefix ? (
                  <p className="text-xs text-destructive">{form.formState.errors.prefix.message}</p>
                ) : null}
              </div>
              <div className="flex flex-col gap-2">
                <Label>{messages.numberSeriesDialog.fields.separator}</Label>
                <Input
                  {...form.register("separator")}
                  placeholder={messages.numberSeriesDialog.placeholders.separator}
                  maxLength={5}
                />
              </div>
              <div className="flex flex-col gap-2">
                <Label>{messages.numberSeriesDialog.fields.padLength}</Label>
                <Input {...form.register("padLength")} type="number" min={0} max={12} />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label>{messages.numberSeriesDialog.fields.resetStrategy}</Label>
                <Select
                  items={RESET_STRATEGIES.map((item) => ({
                    label: messages.common.resetStrategyLabels[item],
                    value: item,
                  }))}
                  value={form.watch("resetStrategy")}
                  onValueChange={(v) =>
                    form.setValue("resetStrategy", v as FormValues["resetStrategy"])
                  }
                >
                  <SelectTrigger className="w-full">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {RESET_STRATEGIES.map((item) => (
                      <SelectItem key={item} value={item}>
                        {messages.common.resetStrategyLabels[item]}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="flex flex-col gap-2">
                <Label>{messages.numberSeriesDialog.fields.scope}</Label>
                <Select
                  items={SCOPES.map((item) => ({
                    label: messages.common.contractScopeLabels[item],
                    value: item,
                  }))}
                  value={form.watch("scope")}
                  onValueChange={(v) => form.setValue("scope", v as FormValues["scope"])}
                >
                  <SelectTrigger className="w-full">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {SCOPES.map((item) => (
                      <SelectItem key={item} value={item}>
                        {messages.common.contractScopeLabels[item]}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <Switch
                checked={form.watch("active")}
                onCheckedChange={(checked) => form.setValue("active", checked)}
              />
              <Label>{messages.numberSeriesDialog.fields.active}</Label>
            </div>

            {conflictingSeries ? (
              <p className="rounded-md border border-destructive/50 bg-destructive/10 p-3 text-xs text-destructive">
                {formatMessage(messages.numberSeriesDialog.duplicateWarning, {
                  prefix: conflictingSeries.prefix,
                  scope: messages.common.contractScopeLabels[conflictingSeries.scope],
                  name: conflictingSeries.name,
                })}
              </p>
            ) : null}
          </DialogBody>
          <DialogFooter>
            <Button type="button" variant="ghost" onClick={() => onOpenChange(false)}>
              {messages.common.cancel}
            </Button>
            <Button
              type="submit"
              disabled={form.formState.isSubmitting || conflictingSeries !== null}
            >
              {form.formState.isSubmitting ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              ) : null}
              {isEditing ? messages.common.saveChanges : messages.numberSeriesDialog.actions.create}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}
